package com.example.trackerinmobile.ui.theme

import androidx.compose.ui.graphics.Color

// ==========================================
// 1. Primitive Colors (Define Figma Variables Here)
// ==========================================

// Primary Brand Colors (Misal: Biru)
val Primary50 = Color(0xFFE3F2FD)
val Primary100 = Color(0xFFBBDEFB)
val Primary500 = Color(0xFF2196F3) // Base Primary
val Primary700 = Color(0xFF1976D2)
val Primary900 = Color(0xFF0D47A1)

// Neutral Colors (Misal: Greyscale)
val Neutral50 = Color(0xFFFAFAFA)
val Neutral100 = Color(0xFFF5F5F5)
val Neutral500 = Color(0xFF9E9E9E)
val Neutral900 = Color(0xFF212121)

// Semantic Colors (Success, Danger, Warning, Info)
val Success = Color(0xFF4CAF50)
val Danger = Color(0xFFF44336)
val Warning = Color(0xFFFFC107)
val Info = Color(0xFF2196F3)

// ==========================================
// Base Colors (Biarkan default M3 untuk referensi)
// ==========================================
val Purple80 = Color(0xFFD0BCFF)
val PurpleGrey80 = Color(0xFFCCC2DC)
val Pink80 = Color(0xFFEFB8C8)

val Purple40 = Color(0xFF6650a4)
val PurpleGrey40 = Color(0xFF625b71)
val Pink40 = Color(0xFF7D5260)

package com.example.trackerinmobile.ui.theme

import android.app.Activity
import android.os.Build
import androidx.compose.foundation.isSystemInDarkTheme
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.darkColorScheme
import androidx.compose.material3.dynamicDarkColorScheme
import androidx.compose.material3.dynamicLightColorScheme
import androidx.compose.material3.lightColorScheme
import androidx.compose.runtime.Composable
import androidx.compose.ui.platform.LocalContext

private val DarkColorScheme = darkColorScheme(
    primary = Purple80,
    secondary = PurpleGrey80,
    tertiary = Pink80
)

private val LightColorScheme = lightColorScheme(
    primary = Purple40,
    secondary = PurpleGrey40,
    tertiary = Pink40

    /* Other default colors to override
    background = Color(0xFFFFFBFE),
    surface = Color(0xFFFFFBFE),
    onPrimary = Color.White,
    onSecondary = Color.White,
    onTertiary = Color.White,
    onBackground = Color(0xFF1C1B1F),
    onSurface = Color(0xFF1C1B1F),
    */
)

@Composable
fun TrackerinMobileTheme(
    darkTheme: Boolean = isSystemInDarkTheme(),
    // Dynamic color is available on Android 12+
    dynamicColor: Boolean = true,
    content: @Composable () -> Unit
) {
    val colorScheme = when {
        dynamicColor && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S -> {
            val context = LocalContext.current
            if (darkTheme) dynamicDarkColorScheme(context) else dynamicLightColorScheme(context)
        }

        darkTheme -> DarkColorScheme
        else -> LightColorScheme
    }

    MaterialTheme(
        colorScheme = colorScheme,
        typography = Typography,
        content = content
    )
}

package com.example.trackerinmobile.ui.theme
import android.app.Activity import android.os.Build import androidx.compose.foundation.isSystemInDarkTheme import androidx.compose.material3.MaterialTheme import androidx.compose.material3.darkColorScheme import androidx.compose.material3.dynamicDarkColorScheme import androidx.compose.material3.dynamicLightColorScheme import androidx.compose.material3.lightColorScheme import androidx.compose.runtime.Composable import androidx.compose.ui.graphics.Color import androidx.compose.ui.platform.LocalContext
private val DarkColorScheme = darkColorScheme( primary = Primary100, secondary = Primary50, tertiary = Neutral500, background = Neutral900, surface = Neutral900 )
private val LightColorScheme = lightColorScheme( primary = Primary500, secondary = Primary700, tertiary = Neutral500, background = Neutral50, surface = Color.White, onPrimary = Color.White, onBackground = Neutral900, error = Danger /* Other default colors to override onSecondary = Color.White, onTertiary = Color.White, onSurface = Color(0xFF1C1B1F), */ )
@Composable fun TrackerinMobileTheme( darkTheme: Boolean = isSystemInDarkTheme(), // Dynamic color is available on Android 12+ dynamicColor: Boolean = true, content: @Composable () -> Unit ) { val colorScheme = when { dynamicColor && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S -> { val context = LocalContext.current if (darkTheme) dynamicDarkColorScheme(context) else dynamicLightColorScheme(context) }
darkTheme -> DarkColorScheme else -> LightColorScheme }
MaterialTheme( colorScheme = colorScheme, typography = Typography, content = content ) }
